## Ethereum Address Field

A field that captures checksum ethereum addresses

### Usage

```ts
import { CardDef, field, contains } from 'https://cardstack.com/base/card-api';
import EthereumAddressField from 'https://cardstack.com/base/ethereum-address';

export class Example extends CardDef {
  @field wallet = contains(EthereumAddressField);
}
```
